"use client";

import type { ReactNode } from "react";

/**
 * Margin apparatus of the essay.
 *
 * FnRef is the superscript marker inside a paragraph; Footnote is the note
 * itself, set in the margin rail (or, on narrow viewports, as an indented
 * note directly beneath its passage). The pair is linked both ways with
 * real anchors — #yb-fnref-N ↔ #yb-fn-N — so keyboard and screen-reader
 * users can travel to the note and back.
 *
 * Footnotes carry data-reveal="margin": at their scroll threshold they
 * slide in from the margin (translateX + opacity, JS-gated behind
 * .yeobaek-js). Without JavaScript, or under prefers-reduced-motion, they
 * are simply present.
 */

export function FnRef({ no }: { no: number }) {
  return (
    <sup className="yeobaek-fnref">
      <a id={`yb-fnref-${no}`} href={`#yb-fn-${no}`} aria-label={`각주 ${no}`}>
        {no}
      </a>
    </sup>
  );
}

type FootnoteProps = {
  no: number;
  children: ReactNode;
};

export default function Footnote({ no, children }: FootnoteProps) {
  return (
    <aside
      id={`yb-fn-${no}`}
      className="yeobaek-fn"
      role="note"
      data-reveal="margin"
    >
      <p className="yeobaek-fn__body">
        <span className="yeobaek-fn__no" aria-hidden="true">
          {no}
        </span>
        {children}{" "}
        <a
          className="yeobaek-fn__back"
          href={`#yb-fnref-${no}`}
          aria-label={`각주 ${no}에서 본문으로 돌아가기`}
        >
          ↩
        </a>
      </p>
    </aside>
  );
}

"use client";

import type { AnchorHTMLAttributes, ReactNode } from "react";

type InkLinkProps = {
  href: string;
  children: ReactNode;
} & AnchorHTMLAttributes<HTMLAnchorElement>;

/**
 * A journal link with the rubber-band underline draw.
 *
 * Anatomy: the text sits over a static graphite hairline (always present —
 * touch and reduced-motion users never lose the affordance), and an inline
 * SVG carries a slightly wobbled oxblood path with pathLength=1. On hover
 * or :focus-visible, CSS transitions stroke-dashoffset 1 → 0 through an
 * overshooting bezier, so the ink draws across and snaps taut like a
 * rubber band. Pure CSS — it works without JavaScript, and under
 * prefers-reduced-motion the oxblood stroke is simply present, undrawn.
 */
export default function InkLink({
  href,
  children,
  className,
  ...rest
}: InkLinkProps) {
  return (
    <a
      href={href}
      className={`yeobaek-link${className ? ` ${className}` : ""}`}
      {...rest}
    >
      <span className="yeobaek-link__text">{children}</span>
      <svg
        className="yeobaek-link__ink"
        viewBox="0 0 160 8"
        preserveAspectRatio="none"
        aria-hidden="true"
        focusable="false"
      >
        <path
          d="M 2 5.4 C 26 3.4, 54 6.8, 82 4.6 S 134 5.8, 158 3.8"
          pathLength={1}
        />
      </svg>
    </a>
  );
}

import { Libre_Caslon_Text, Nanum_Myeongjo } from "next/font/google";

/**
 * The two voices of the journal:
 * Nanum Myeongjo — the Korean serif; every Hangul glyph, the masthead 여백,
 * the essay's first language. It is the journal's own hand.
 * Libre Caslon Text — the Latin text face; transcreations, folios (italic),
 * the drop cap, captions. It answers, it never interrupts.
 *
 * styles.css consumes these as var(--font-nanum-myeongjo) /
 * var(--font-libre-caslon); page.tsx applies the .variable classes on the
 * entry root. The body stack puts Caslon first so Latin resolves there and
 * Hangul falls through into Myeongjo even without a lang attribute.
 */
export const nanumMyeongjo = Nanum_Myeongjo({
  weight: ["400", "700", "800"],
  subsets: ["latin"],
  variable: "--font-nanum-myeongjo",
  display: "swap",
});

export const libreCaslon = Libre_Caslon_Text({
  weight: ["400", "700"],
  style: ["normal", "italic"],
  subsets: ["latin"],
  variable: "--font-libre-caslon",
  display: "swap",
});

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. Pre-reveal states (the quiet fade-rise
 * for text, the margin slide for footnotes marked data-reveal="margin")
 * live in styles.css and are gated behind the `.yeobaek-js` root class, so
 * the whole journal is plainly readable when JavaScript never runs — a
 * magazine must degrade to a clean document.
 *
 * Elements that intersect in the same observer batch are staggered 80ms
 * apart via transition-delay, so a screenful never fades as one slab.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          el.style.transitionDelay = `${batch * 80}ms`;
          el.classList.add("is-visible");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.12, rootMargin: "0px 0px -8% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Drives a 0→1 scroll progress for a pinned essay spread, written to the
 * element as the `--yb-scrub` custom property. The tipped-in figure plate
 * consumes it in CSS: `stroke-dashoffset: calc(1 - var(--yb-scrub))` on
 * pathLength=1 strokes, so the ink draws exactly as far as the reader has
 * scrolled — and no further.
 *
 * Discipline:
 * - All geometry is measured inside rAF (one getBoundingClientRect read,
 *   then one custom-property write — read before write, no layout thrash).
 * - The raw progress is lerp-smoothed with a dt-normalized factor so a
 *   120Hz display doesn't scrub twice as fast as a 60Hz one.
 * - An IntersectionObserver starts/stops the loop, so an offscreen spread
 *   costs zero frames.
 * - Disabled (reduced motion) or never mounted (no JS): the CSS fallback
 *   `var(--yb-scrub, 1)` and the root default of 1 leave every stroke
 *   fully drawn — a finished plate, statically tipped in.
 */
export function useScrollScrub<T extends HTMLElement>(disabled: boolean) {
  const ref = useRef<T | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    if (disabled) {
      el.style.setProperty("--yb-scrub", "1");
      return;
    }

    let raf = 0;
    let last = 0;
    let value: number | null = null;

    const frame = (now: number) => {
      raf = requestAnimationFrame(frame);
      const dt = Math.min(Math.max(now - last, 1), 48);
      last = now;

      // Read phase: one rect, one viewport height.
      const rect = el.getBoundingClientRect();
      const vh = window.innerHeight || 1;

      // The scrub runs from "spread top at 70% of the viewport" across
      // 85% of the spread's height, capped at ~1.1 viewports so tall
      // single-column (mobile) spreads still finish while the plate is
      // in view.
      const span = Math.max(Math.min(rect.height * 0.85, vh * 1.1), 1);
      const raw = (vh * 0.7 - rect.top) / span;
      const target = Math.min(1, Math.max(0, raw));

      if (value === null) {
        value = target; // first frame: no animated catch-up flash
      } else {
        value += (target - value) * (1 - Math.pow(0.86, dt / 16.7));
        if (Math.abs(target - value) < 0.0005) value = target;
      }

      // Write phase.
      el.style.setProperty("--yb-scrub", value.toFixed(4));
    };

    const start = () => {
      if (raf) return;
      last = performance.now();
      raf = requestAnimationFrame(frame);
    };
    const stop = () => {
      if (!raf) return;
      cancelAnimationFrame(raf);
      raf = 0;
    };

    if (!("IntersectionObserver" in window)) {
      start();
      return stop;
    }

    const io = new IntersectionObserver(
      (hits) => {
        for (const hit of hits) {
          if (hit.isIntersecting) start();
          else stop();
        }
      },
      { rootMargin: "30% 0px 30% 0px" },
    );
    io.observe(el);

    return () => {
      stop();
      io.disconnect();
    };
  }, [disabled]);

  return ref;
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { libreCaslon, nanumMyeongjo } from "./fonts";
import Masthead from "./components/Masthead";
import LeadEssay from "./components/LeadEssay";
import EmptinessGallery from "./components/EmptinessGallery";
import Colophon from "./components/Colophon";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";

/**
 * 여백 YEOBAEK — The Journal of Blank Space, No. 07.
 * A bilingual literary magazine about yeobaek — negative space in Korean
 * art and life. The page is the issue itself: an ivory cover that
 * demonstrates its own subject, a lead essay whose tipped-in plates pin
 * while the text flows past, margin footnotes that arrive quietly, and a
 * gallery of mostly-empty plates. The discipline throughout is typographic
 * rhythm and the deliberate use of emptiness — whitespace is the design.
 *
 * `.yeobaek-js` is added on mount so every scroll-driven style is JS-gated:
 * with JavaScript disabled the whole issue is simply readable, strokes
 * drawn, footnotes present — a clean printed document.
 */
export default function YeobaekPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and it never changes once set.
    rootRef.current?.classList.add("yeobaek-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "yeobaek" }, "*");
  }, []);

  return (
    <div
      id="yeobaek-top"
      ref={rootRef}
      className={`${nanumMyeongjo.variable} ${libreCaslon.variable} yeobaek-root`}
    >
      <div ref={revealRef} className="yeobaek-issue">
        <Masthead />
        <main>
          <LeadEssay />
          <EmptinessGallery />
        </main>
        <Colophon />
      </div>
    </div>
  );
}

/* ==========================================================================
   여백 YEOBAEK — The Journal of Blank Space · No. 07
   editorial-serif · ink on ivory · whitespace is the design
   Scoped by convention to .yeobaek-root; classes prefixed yeobaek-.
   ========================================================================== */

.yeobaek-root {
  /* -- palette ------------------------------------------------------------ */
  --yb-ivory: #faf6ef;             /* the page — everything happens against it */
  --yb-plate: #fffdf8;             /* tipped-in plate paper, a half-step brighter */
  --yb-ink: #232020;               /* text ink — 15.0:1 on ivory */
  --yb-ink-soft: rgba(35, 32, 32, 0.72); /* ≈ #5f5c5a — 6.2:1, secondary text */
  --yb-oxblood: #7d2a26;           /* the single accent — 8.7:1 on ivory */
  --yb-graphite: #8f8a82;          /* rules ONLY (3.2:1) — never text */
  --yb-rule: rgba(143, 138, 130, 0.55);      /* derived: standard hairline */
  --yb-rule-faint: rgba(143, 138, 130, 0.32); /* derived: plate edges, column rule */
  --yb-shadow: rgba(35, 32, 32, 0.14);        /* derived: tip-in shadow */

  /* -- type ---------------------------------------------------------------- */
  --yb-font-latin: var(--font-libre-caslon), "Libre Caslon Text", Georgia, serif;
  --yb-font-kr: var(--font-nanum-myeongjo), "Nanum Myeongjo", serif;
  /* Caslon first: Latin resolves there, Hangul falls through into Myeongjo */
  --yb-font-stack: var(--font-libre-caslon), var(--font-nanum-myeongjo),
    Georgia, serif;

  /* -- motion --------------------------------------------------------------- */
  --yb-ease-out: cubic-bezier(0.16, 1, 0.3, 1);   /* reveals: fast in, long tail */
  --yb-ease-ink: cubic-bezier(0.4, 0, 0.2, 1);    /* stroke draws: even, unhurried */
  --yb-ease-band: cubic-bezier(0.32, 1.42, 0.5, 1); /* underline: draw + snap taut */
  --yb-reveal-ms: 700ms;

  /* Scroll scrub default: 1 = every stroke fully drawn. JS lowers it per
     spread; reduced-motion and no-JS never touch it. */
  --yb-scrub: 1;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--yb-ivory);
  color: var(--yb-ink);
  font-family: var(--yb-font-stack);
  font-size: clamp(16px, 0.45vw + 14px, 19px);
  line-height: 1.8;
  overflow-x: hidden;
  overflow-x: clip;
}

/* Korean is the first language of this journal: Myeongjo, keep-all line
   breaking, a touch of negative tracking. */
.yeobaek-root :lang(ko) {
  font-family: var(--yb-font-kr);
  letter-spacing: -0.005em;
  word-break: keep-all;
}

/* Oxblood selection, scoped to the entry root */
.yeobaek-root ::selection {
  background: var(--yb-oxblood);
  color: var(--yb-ivory);
}

/* Keyboard focus: an oxblood ring, offset like a registration mark */
.yeobaek-root :focus-visible {
  outline: 2px solid var(--yb-oxblood);
  outline-offset: 3px;
  border-radius: 1px;
}

.yeobaek-issue {
  position: relative;
}

/* ==========================================================================
   Links — the rubber-band underline draw
   A static graphite hairline is always present (touch users never lose the
   affordance); the oxblood SVG stroke draws over it on hover/focus with an
   overshooting bezier. Pure CSS: works without JS.
   ========================================================================== */

.yeobaek-link {
  position: relative;
  display: inline-block;
  color: var(--yb-ink);
  text-decoration: none;
  border-bottom: 1px solid var(--yb-rule);
  padding-bottom: 1px;
  transition: color 300ms var(--yb-ease-ink);
}

.yeobaek-link:hover,
.yeobaek-link:focus-visible {
  color: var(--yb-oxblood);
}

.yeobaek-link__ink {
  position: absolute;
  left: -2px;
  right: -2px;
  bottom: -4px;
  height: 8px;
  width: calc(100% + 4px);
  overflow: visible;
  pointer-events: none;
}

.yeobaek-link__ink path {
  fill: none;
  stroke: var(--yb-oxblood);
  stroke-width: 1.6;
  stroke-linecap: round;
  vector-effect: non-scaling-stroke;
  stroke-dasharray: 1 1;
  stroke-dashoffset: 1;
  transition: stroke-dashoffset 220ms var(--yb-ease-ink);
}

.yeobaek-link:hover .yeobaek-link__ink path,
.yeobaek-link:focus-visible .yeobaek-link__ink path {
  stroke-dashoffset: 0;
  transition: stroke-dashoffset 640ms var(--yb-ease-band);
}

/* ==========================================================================
   Kicker — the journal's one recurring ornament: an oxblood hairline,
   then a small-tracked bilingual label
   ========================================================================== */

.yeobaek-kicker {
  margin: 0 0 1.4rem;
  font-family: var(--yb-font-latin);
  font-size: 0.72rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: var(--yb-ink-soft);
}

.yeobaek-kicker::before {
  content: "";
  display: block;
  width: 3rem;
  height: 1px;
  margin-bottom: 1.1rem;
  background: var(--yb-oxblood);
}

.yeobaek-kicker :lang(ko) {
  letter-spacing: 0.18em;
}

/* ==========================================================================
   01 · Cover — the masthead demonstrates yeobaek
   ========================================================================== */

.yeobaek-cover {
  position: relative;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
  min-height: 100svh;
  max-width: 82rem;
  margin-inline: auto;
  padding: clamp(24px, 6vw, 76px);
}

.yeobaek-cover__folio {
  position: absolute;
  top: clamp(24px, 6vw, 76px);
  right: clamp(24px, 6vw, 76px);
  margin: 0;
  font-family: var(--yb-font-latin);
  font-style: italic;
  font-size: 1rem;
  color: var(--yb-ink-soft);
}

.yeobaek-cover__id {
  margin-top: clamp(3.5rem, 18vh, 16rem);
  max-width: 44rem;
}

.yeobaek-name {
  margin: 0 0 1.6rem;
  font-family: var(--yb-font-kr);
  font-weight: 800;
  font-size: clamp(5rem, 21vw, 15rem);
  line-height: 0.98;
  letter-spacing: -0.015em;
}

.yeobaek-name__ch {
  display: inline-block;
}

.yeobaek-cover__deck {
  margin: 0 0 2rem;
  font-family: var(--yb-font-latin);
  font-size: clamp(0.78rem, 1.4vw, 0.95rem);
  letter-spacing: 0.26em;
  text-transform: uppercase;
}

/* THE oxblood hairline of the cover */
.yeobaek-cover__rule {
  width: 5.5rem;
  height: 1px;
  margin: 0 0 1.3rem;
  background: var(--yb-oxblood);
}

.yeobaek-cover__issue {
  margin: 0;
  font-size: 0.95rem;
  color: var(--yb-ink-soft);
}

.yeobaek-cover__foot {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-end;
  justify-content: space-between;
  gap: 1.2rem 3rem;
  margin-top: auto;
  padding-top: 4rem;
}

.yeobaek-cover__begin {
  margin: 0;
  font-size: 0.95rem;
}

.yeobaek-cover__epigraph {
  margin: 0;
  max-width: 20rem;
  font-size: 0.88rem;
  line-height: 1.7;
  color: var(--yb-ink-soft);
  text-align: right;
}

.yeobaek-cover__epigraph em {
  display: block;
  font-family: var(--yb-font-latin);
}

/* Cover choreography — JS-gated; the no-JS cover is simply complete */
.yeobaek-js .yeobaek-name__ch {
  animation: yb-rise 1100ms var(--yb-ease-out) both;
  animation-delay: calc(120ms + var(--yb-ci, 0) * 190ms);
}

.yeobaek-js .yeobaek-cover__folio {
  animation: yb-rise 900ms var(--yb-ease-out) 340ms both;
}

.yeobaek-js .yeobaek-cover__deck {
  animation: yb-rise 900ms var(--yb-ease-out) 520ms both;
}

.yeobaek-js .yeobaek-cover__rule {
  transform-origin: left center;
  animation: yb-rule-draw 1000ms var(--yb-ease-out) 680ms both;
}

.yeobaek-js .yeobaek-cover__issue {
  animation: yb-rise 900ms var(--yb-ease-out) 800ms both;
}

.yeobaek-js .yeobaek-cover__foot {
  animation: yb-rise 1000ms var(--yb-ease-out) 1020ms both;
}

/* ==========================================================================
   02 · Lead essay — blocks, margin rail, measure
   ========================================================================== */

.yeobaek-essay {
  padding: clamp(96px, 16vh, 200px) clamp(20px, 6vw, 48px);
}

.yeobaek-essay__head {
  max-width: 58rem;
  margin: 0 auto clamp(4rem, 9vh, 7rem);
}

.yeobaek-essay__title {
  margin: 0 0 0.6rem;
  font-weight: 700;
  font-size: clamp(2.1rem, 5vw, 3.6rem);
  line-height: 1.25;
}

.yeobaek-essay__sub {
  margin: 0 0 1.6rem;
  font-family: var(--yb-font-latin);
  font-style: italic;
  font-size: clamp(1rem, 2vw, 1.25rem);
  color: var(--yb-ink-soft);
}

.yeobaek-essay__byline {
  margin: 0;
  font-size: 0.85rem;
  letter-spacing: 0.04em;
  color: var(--yb-ink-soft);
}

/* Passage: measured text + margin rail */
.yeobaek-block {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 1.4rem 3.5rem;
  max-width: 58rem;
  margin-inline: auto;
}

.yeobaek-block + .yeobaek-block {
  margin-top: clamp(1.5rem, 4vh, 3rem);
}

.yeobaek-block__text {
  max-width: 36rem;
}

.yeobaek-block__margin {
  max-width: 26rem;
}

@media (min-width: 1080px) {
  .yeobaek-block {
    grid-template-columns: minmax(0, 36rem) 15rem;
  }

  .yeobaek-block__text {
    grid-column: 1;
  }

  .yeobaek-block__margin {
    grid-column: 2;
    grid-row: 1;
    align-self: start;
    max-width: none;
    /* sit the note roughly beside its reference, not at the block's top */
    padding-top: 0.4rem;
  }
}

/* Paragraph rhythm: the KO paragraph leads, its EN transcreation answers */
.yeobaek-p {
  margin: 0;
}

.yeobaek-p--ko {
  margin-bottom: 0.8rem;
  line-height: 2.05;
}

.yeobaek-p--en {
  margin-bottom: 2.4rem;
  font-family: var(--yb-font-latin);
  font-size: 0.95em;
  line-height: 1.78;
  color: var(--yb-ink-soft);
}

.yeobaek-spread__text > .yeobaek-p--en:last-child,
.yeobaek-block__text > .yeobaek-p--en:last-child {
  margin-bottom: 0;
}

/* Drop cap — Libre Caslon, oxblood, four lines deep */
.yeobaek-p--drop::first-letter {
  float: left;
  padding: 0.08em 0.14em 0 0;
  font-family: var(--yb-font-latin);
  font-size: 4.6em;
  line-height: 0.76;
  color: var(--yb-oxblood);
}

/* Footnote reference marker */
.yeobaek-fnref {
  font-size: 0.62em;
  line-height: 0;
  vertical-align: super;
}

.yeobaek-fnref a {
  padding: 0.1em 0.2em;
  font-family: var(--yb-font-latin);
  font-style: italic;
  color: var(--yb-oxblood);
  text-decoration: none;
}

.yeobaek-fnref a:hover {
  text-decoration: underline;
  text-underline-offset: 2px;
}

/* Margin footnotes */
.yeobaek-fn {
  border-top: 1px solid var(--yb-rule-faint);
  padding-top: 0.7rem;
  font-size: 0.8rem;
  line-height: 1.68;
  color: var(--yb-ink-soft);
}

.yeobaek-fn__body {
  margin: 0;
}

.yeobaek-fn__no {
  margin-right: 0.5em;
  font-family: var(--yb-font-latin);
  font-style: italic;
  font-weight: 700;
  color: var(--yb-oxblood);
}

.yeobaek-fn em {
  font-family: var(--yb-font-latin);
}

.yeobaek-fn__back {
  margin-left: 0.35em;
  color: var(--yb-oxblood);
  text-decoration: none;
}

.yeobaek-fn__back:hover {
  text-decoration: underline;
  text-underline-offset: 2px;
}

@media (max-width: 1079.98px) {
  .yeobaek-block__margin .yeobaek-fn {
    border-top: 0;
    border-left: 2px solid var(--yb-rule-faint);
    padding: 0.1rem 0 0.1rem 1rem;
    margin-bottom: 2.4rem;
  }
}

/* ==========================================================================
   03 · Spreads — the tipped-in plate that pins
   ========================================================================== */

.yeobaek-spread {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: clamp(2.5rem, 6vh, 4rem) clamp(3rem, 6vw, 6rem);
  max-width: 74rem;
  margin: clamp(5rem, 14vh, 10rem) auto;
}

.yeobaek-spread__text {
  max-width: 36rem;
}

@media (min-width: 880px) {
  .yeobaek-spread {
    grid-template-columns: minmax(0, 5fr) minmax(0, 7fr);
  }

  .yeobaek-spread--flip {
    grid-template-columns: minmax(0, 7fr) minmax(0, 5fr);
  }

  .yeobaek-spread--flip .yeobaek-spread__fig {
    order: 2;
  }

  /* The pin: sticky inside the spread's full-height figure column.
     It holds while the essay flows past, then releases with the spread. */
  .yeobaek-spread__fig .yeobaek-figure {
    position: sticky;
    top: clamp(4.5rem, 14vh, 8rem);
  }
}

/* Figures & plates — tipped-in prints */
.yeobaek-figure {
  margin: 0;
  max-width: min(24rem, 100%);
}

.yeobaek-spread--flip .yeobaek-spread__fig .yeobaek-figure {
  margin-left: auto;
}

.yeobaek-plate {
  background: var(--yb-plate);
  border: 1px solid var(--yb-rule-faint);
  padding: clamp(0.9rem, 2vw, 1.4rem);
  box-shadow:
    0 14px 34px -22px var(--yb-shadow),
    0 2px 6px rgba(35, 32, 32, 0.05);
  transform: rotate(-0.6deg);
}

.yeobaek-spread--flip .yeobaek-plate,
.yeobaek-gallery__item--right .yeobaek-plate {
  transform: rotate(0.5deg);
}

.yeobaek-plate__art {
  display: block;
  width: 100%;
  height: auto;
}

.yeobaek-figure__cap {
  display: grid;
  gap: 0.15rem;
  margin-top: 0.95rem;
  font-size: 0.8rem;
  line-height: 1.6;
  color: var(--yb-ink-soft);
}

.yeobaek-figure__cap em {
  font-family: var(--yb-font-latin);
}

/* The scrubbed ink: pathLength=1 strokes whose dashoffset is the inverse
   of the spread's scroll progress. Default --yb-scrub is 1 (root), so
   without JS — or with reduced motion — every stroke is simply drawn. */
.yeobaek-stroke {
  fill: none;
  stroke: var(--yb-ink);
  stroke-linecap: round;
  stroke-dasharray: 1 1;
  stroke-dashoffset: calc(1 - var(--yb-scrub, 1));
}

.yeobaek-stroke--broad {
  stroke-width: 12;
}

.yeobaek-stroke--thin {
  stroke-width: 3.5;
  opacity: 0.55;
}

.yeobaek-stroke--pillar {
  stroke-width: 9;
}

/* The red seal arrives only when the interval plate is nearly complete:
   opacity is clamped to [0,1] by the browser, so this maps scrub
   0.833→1.0 onto 0→1. Reduced motion / no JS: scrub is 1 → seal present. */
.yeobaek-seal {
  fill: var(--yb-oxblood);
  opacity: calc(var(--yb-scrub, 1) * 6 - 5);
}

/* ==========================================================================
   04 · Coda — the essay's two-column close
   ========================================================================== */

.yeobaek-codasec {
  max-width: 58rem;
  margin: clamp(4rem, 10vh, 7rem) auto 0;
}

.yeobaek-codasec__title {
  margin: 0 0 2.2rem;
  font-weight: 700;
  font-size: 1.15rem;
  letter-spacing: 0.06em;
}

.yeobaek-coda {
  column-gap: 4rem;
  column-rule: 1px solid var(--yb-rule-faint);
  max-width: 52rem;
}

.yeobaek-coda .yeobaek-p {
  break-inside: avoid;
}

@media (min-width: 900px) {
  .yeobaek-coda {
    column-count: 2;
  }
}

/* ==========================================================================
   05 · Gallery of emptiness
   ========================================================================== */

.yeobaek-gallery {
  padding: clamp(96px, 18vh, 220px) clamp(20px, 6vw, 48px);
}

.yeobaek-gallery__head {
  max-width: 58rem;
  margin: 0 auto clamp(5rem, 12vh, 9rem);
}

.yeobaek-gallery__title {
  margin: 0 0 0.5rem;
  font-weight: 700;
  font-size: clamp(1.8rem, 4vw, 2.8rem);
  line-height: 1.3;
}

.yeobaek-gallery__sub {
  margin: 0;
  font-family: var(--yb-font-latin);
  font-style: italic;
  font-size: 1.05rem;
  color: var(--yb-ink-soft);
}

/* Plates hang on the wall with vast air between them */
.yeobaek-gallery__wall {
  display: flex;
  flex-direction: column;
  gap: clamp(6rem, 18vh, 14rem);
  max-width: 64rem;
  margin-inline: auto;
}

.yeobaek-gallery__item {
  margin: 0;
  width: min(26rem, 100%);
}

.yeobaek-gallery__item--right {
  align-self: flex-end;
}

.yeobaek-gallery__item--center {
  align-self: center;
}

/* Gallery strokes draw once at their reveal threshold (time-based, unlike
   the essay's scroll-scrubbed plates). Hidden state exists only under
   .yeobaek-js; the no-JS gallery is finished. */
.yeobaek-gstroke {
  fill: none;
  stroke: var(--yb-ink);
  stroke-width: 1.6;
  stroke-linecap: round;
  stroke-dasharray: 1 1;
  stroke-dashoffset: 0;
  opacity: 0.8;
}

.yeobaek-gstroke--d2 {
  stroke-width: 1.3;
  opacity: 0.6;
}

.yeobaek-gstroke--d3 {
  stroke-width: 1.1;
  opacity: 0.45;
}

.yeobaek-js .yeobaek-gallery [data-reveal] .yeobaek-gstroke {
  stroke-dashoffset: 1;
}

.yeobaek-js .yeobaek-gallery [data-reveal].is-visible .yeobaek-gstroke {
  stroke-dashoffset: 0;
  transition: stroke-dashoffset 1500ms var(--yb-ease-ink) 250ms;
}

.yeobaek-js .yeobaek-gallery [data-reveal].is-visible .yeobaek-gstroke--d2 {
  transition-delay: 500ms;
}

.yeobaek-js .yeobaek-gallery [data-reveal].is-visible .yeobaek-gstroke--d3 {
  transition-delay: 750ms;
}

/* Plate IV — 숨: one syllable, low in the field */
.yeobaek-plate--breath {
  position: relative;
  aspect-ratio: 360 / 300;
}

.yeobaek-plate--breath span {
  position: absolute;
  left: 13%;
  bottom: 13%;
  font-size: clamp(1.9rem, 4vw, 2.8rem);
  font-weight: 700;
  color: var(--yb-ink);
}

/* Plate V — deliberately empty */
.yeobaek-plate--void {
  aspect-ratio: 360 / 300;
}

/* ==========================================================================
   06 · Colophon
   ========================================================================== */

.yeobaek-colophon {
  padding: clamp(80px, 14vh, 160px) clamp(20px, 6vw, 48px)
    clamp(96px, 16vh, 180px);
}

.yeobaek-colophon__inner {
  max-width: 58rem;
  margin-inline: auto;
}

.yeobaek-colophon__title {
  margin: 0 0 0.8rem;
  font-weight: 800;
  font-size: clamp(2rem, 5vw, 3.2rem);
  line-height: 1.1;
}

.yeobaek-colophon__statement {
  margin: 0 0 3rem;
  max-width: 34rem;
  font-size: 0.95rem;
  line-height: 1.8;
  color: var(--yb-ink-soft);
}

.yeobaek-colophon__statement em {
  font-family: var(--yb-font-latin);
}

.yeobaek-colophon__masthead {
  margin: 0 0 3.2rem;
  max-width: 44rem;
}

.yeobaek-colophon__masthead > div {
  display: flex;
  flex-wrap: wrap;
  gap: 0.2rem 1.5rem;
  padding: 0.65rem 0;
  border-bottom: 1px dotted var(--yb-rule);
}

.yeobaek-colophon__masthead dt {
  flex: 0 0 11.5rem;
  font-family: var(--yb-font-latin);
  font-size: 0.72rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--yb-ink-soft);
  line-height: 2.2;
}

.yeobaek-colophon__masthead dt :lang(ko) {
  letter-spacing: 0.1em;
}

.yeobaek-colophon__masthead dd {
  flex: 1 1 16rem;
  margin: 0;
  font-size: 0.95rem;
}

.yeobaek-colophon__legal {
  margin: 0 0 1.6rem;
  font-size: 0.9rem;
  color: var(--yb-ink-soft);
}

.yeobaek-colophon__top {
  margin: 0;
  font-size: 0.9rem;
}

/* ==========================================================================
   Scroll reveals — JS-gated pre-state, transform/opacity only
   ========================================================================== */

.yeobaek-js [data-reveal] {
  opacity: 0;
  transform: translateY(14px);
  transition:
    opacity var(--yb-reveal-ms) var(--yb-ease-out),
    transform var(--yb-reveal-ms) var(--yb-ease-out);
  will-change: opacity, transform;
}

/* Footnotes slide in from the margin instead of rising */
.yeobaek-js [data-reveal="margin"] {
  transform: translateX(22px);
}

.yeobaek-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform / opacity only
   ========================================================================== */

@keyframes yb-rise {
  from {
    opacity: 0;
    transform: translateY(0.22em);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

@keyframes yb-rule-draw {
  from {
    transform: scaleX(0);
  }
  to {
    transform: scaleX(1);
  }
}

/* ==========================================================================
   Reduced motion — one beautiful static issue
   - cover: no choreography, fully composed
   - reveals: present, no motion
   - footnotes: present, no slide
   - figures: static tipped-in plates, no pin
   - strokes: fully drawn (scrub stays 1), no draw transitions
   - underlines: simply present, no rubber-band
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .yeobaek-js .yeobaek-name__ch,
  .yeobaek-js .yeobaek-cover__folio,
  .yeobaek-js .yeobaek-cover__deck,
  .yeobaek-js .yeobaek-cover__rule,
  .yeobaek-js .yeobaek-cover__issue,
  .yeobaek-js .yeobaek-cover__foot {
    animation: none;
  }

  .yeobaek-js [data-reveal],
  .yeobaek-js [data-reveal="margin"] {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .yeobaek-spread__fig .yeobaek-figure {
    position: static;
  }

  .yeobaek-link .yeobaek-link__ink path,
  .yeobaek-link:hover .yeobaek-link__ink path,
  .yeobaek-link:focus-visible .yeobaek-link__ink path {
    stroke-dashoffset: 0;
    transition: none;
  }

  .yeobaek-js .yeobaek-gallery [data-reveal] .yeobaek-gstroke,
  .yeobaek-js .yeobaek-gallery [data-reveal].is-visible .yeobaek-gstroke {
    stroke-dashoffset: 0;
    transition: none;
  }
}
